#include <iostream>
#include <string>

using namespace std;

long long factorial(int n) {
    long long fact = 1;
    for (int i = 1; i <= n; i++) {
        fact *= i;
    }
    return fact;
}

bool isVowel(char c) {
    return c == 'A' || c == 'E' || c == 'I' || c == 'O' || c == 'U';
}

int main() {
    string s;
    cin >> s;

    int consonant_count = 0;
    for (char ch : s) {
        if (!isVowel(ch)) {
            consonant_count++;
        }
    }
    cout << factorial(consonant_count) << endl;   
    return 0;
}

