def factorial(n):
    fact = 1
    for i in range(1, n + 1):
        fact *= i
    return fact

def is_vowel(c):
    return c in "AEIOU"

s = input().strip()
consonant_count = sum(1 for ch in s if not is_vowel(ch))

print(factorial(consonant_count))

code.C:
#include <stdio.h>
#include <string.h>
#include <stdbool.h>

long long factorial(int n) {
    long long fact = 1;
    for (int i = 1; i <= n; i++) {
        fact *= i;
    }
    return fact;
}

bool isVowel(char c) {
    return c == 'A' || c == 'E' || c == 'I' || c == 'O' || c == 'U';
}

int main() {
    char s[1001];
    scanf("%s", s);

    int consonant_count = 0;
    for (int i = 0; i < strlen(s); i++) {
        if (!isVowel(s[i])) {
            consonant_count++;
        }
    }

    printf("%lld\n", factorial(consonant_count));
    return 0;
}

code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static long factorial(int n) {
        long fact = 1;
        for (int i = 1; i <= n; i++) {
            fact *= i;
        }
        return fact;
    }

    public static boolean isVowel(char c) {
        return c == 'A' || c == 'E' || c == 'I' || c == 'O' || c == 'U';
    }

    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int consonantCount = 0;

        for (char ch : s.toCharArray()) {
            if (!isVowel(ch)) {
                consonantCount++;
            }
        }
        System.out.println(factorial(consonantCount));
        sc.close();
    }
}

